import{_ as t,o as a,c as i,a0 as r}from"./chunks/framework.D7jNN1Sc.js";const m=JSON.parse('{"title":"Material Copier","description":"","frontmatter":{},"headers":[],"relativePath":"en/features/material-copier.md","filePath":"en/features/material-copier.md"}'),o={name:"en/features/material-copier.md"};function c(d,e,s,n,l,h){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="material-copier" tabindex="-1">Material Copier <a class="header-anchor" href="#material-copier" aria-label="Permalink to &quot;Material Copier&quot;">​</a></h1><p>Copy &amp; paste materials from multiple selected GameObjects to GameObjects with matching names. Supports instant FBX setup and outfit color variation. Works with both MeshRenderer and SkinnedMeshRenderer.</p><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><ol><li>Select source GameObjects (multiple selection supported) → Right-click → <code>Copy Materials</code></li><li>Select target GameObjects → Right-click → <code>Paste Materials</code></li></ol><p>Materials are applied to objects with matching names (e.g., <code>Head</code> → <code>Head</code>, <code>Body</code> → <code>body</code>).</p><h2 id="matching-specifications" tabindex="-1">Matching Specifications <a class="header-anchor" href="#matching-specifications" aria-label="Permalink to &quot;Matching Specifications&quot;">​</a></h2><p>Source and target objects are automatically matched in the following priority order. Only objects with a Renderer are considered.</p><table tabindex="0"><thead><tr><th>Priority</th><th>Method</th><th>Example</th></tr></thead><tbody><tr><td>1</td><td>Exact relative path match (excluding root name)</td><td><code>Outfit/Jacket</code> → <code>Outfit/Jacket</code></td></tr><tr><td>2</td><td>Name match at the same hierarchy depth</td><td><code>Outfit_A/Outer/Accessories/Earing</code> (depth 3) → <code>Outfit_B/Inner/Accessories/Earing</code> (depth 3)</td></tr><tr><td>3</td><td>Name match (any depth, closest depth preferred)</td><td><code>Outfit/Outer/Jacket</code> (depth 3) → <code>Jacket</code> (depth 1)</td></tr><tr><td>4</td><td>Case-insensitive name match</td><td><code>earing</code> → <code>Earing</code></td></tr><tr><td>5</td><td>Similar name match (suffix normalization, common base name)</td><td><code>Ribbon_blue</code> → <code>Ribbon_red</code>, <code>Hair.001</code> → <code>Hair.002</code></td></tr></tbody></table><p>When multiple candidates remain at the same priority, hierarchy path similarity, ancestor context matching, depth proximity, and Levenshtein distance are used for selection.</p><p>This matching specification is also shared by MA Material Helper.</p><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>Right-click in Hierarchy → <code>Kanameliser Editor Plus &gt; Copy Materials / Paste Materials</code></p>',12)])])}const u=t(o,[["render",c]]);export{m as __pageData,u as default};
